#include <fstream>
#include <iostream>
#include <string>
int main() {
  std::ifstream input("courses.txt");
  if (!input) {
    std::cerr << "Could not open courses.txt\n";
    return 1;
  }
  std::string line;
  while (std::getline(input, line)) {
    std::cout << line << "\n";
  }
}
